				DROP TABLE IF EXISTS DETALLES;
				create TEMPORARY TABLE DETALLES
					select * from REG_DETALLES where regmovim_id = '[__id_regmovimheader__]';

delete REG_IMPUTACIONESDETALLES.* from REG_IMPUTACIONESDETALLES join  DETALLES on id_regdetalle = regdetallefac_id and regmovim_id = '[__id_regmovimheader__]';
